export type LangCode = 'en'|'es'|'pt'|'fr'|'de'|'it'|'nl'|'zh'|'ja'|'ru';
export type LangMap  = Record<LangCode, string>;

export interface VocabItem { id: string; emoji: string; w: LangMap; }
export interface LearnTopic { id: string; emoji: string; title: string; items: VocabItem[]; }
export interface LearnLevel { level: 1|2|3|4|5|6; title: string; emoji: string; color: string; topics: LearnTopic[]; }
export type StepCard = { type: 'card'; item: VocabItem };
export type StepQuiz = { type: 'quiz'; item: VocabItem; nativeWord: string; options: string[]; correctIdx: number; };
export type LessonStep = StepCard | StepQuiz;

const SUPPORTED: LangCode[] = ['en','es','pt','fr','de','it','nl','zh','ja','ru'];

export function dl(code: string): LangCode {
  if (SUPPORTED.includes(code as LangCode)) return code as LangCode;
  const base = code.split('-')[0] as LangCode;
  return SUPPORTED.includes(base) ? base : 'en';
}

const v = (id: string, emoji: string, en: string, es: string, pt: string, fr: string, de: string, it: string, nl: string, zh: string, ja: string, ru: string): VocabItem =>
  ({ id, emoji, w: { en, es, pt, fr, de, it, nl, zh, ja, ru } });

